        let accessibilityHint: String?
        let accessibilityTraits: [String]?

        init(
            title: String,
            action: String,
            style: String? = nil,
            disabled: Bool? = nil,
            accessibilityLabel: String? = nil,
            accessibilityHint: String? = nil,
            accessibilityTraits: [String]? = nil
        ) {
            self.title = title
            self.action = action
            self.style = style
            self.disabled = disabled
            self.accessibilityLabel = accessibilityLabel
            self.accessibilityHint = accessibilityHint
            self.accessibilityTraits = accessibilityTraits
        }
    }

    static let type = "Button"
    static let description = "Interactive button that triggers an action"
    static let hasChildren = false
    static let propsSchemaDescription = """
        { title: string (required), action: string (required), style?: string, disabled?: boolean, \
        accessibilityLabel?: string, accessibilityHint?: string, accessibilityTraits?: string[] }
        """
    static let allowedPropKeys: Set<String> = [
        "title", "action", "style", "disabled",
        "accessibilityLabel", "accessibilityHint", "accessibilityTraits"
    ]

    static func validate(props: Props) throws {
        if props.title.isEmpty {
            throw UIComponentValidationError.invalidPropValue(
                component: type,
                prop: "title",
                reason: "Title cannot be empty"
            )
        }
        if props.action.isEmpty {
            throw UIComponentValidationError.invalidPropValue(
                component: type,
                prop: "action",
                reason: "Action cannot be empty"
            )
        }
    }

    static func validateWithCatalog(
        props: Props,
        actions: Set<String>,
        validators: Set<String>
    ) throws {
        // Basic validation
        try validate(props: props)

        // Catalog-aware validation: check action exists in registered actions
        if !actions.contains(props.action) {
            throw UIComponentValidationError.unknownAction(
                component: type,
                action: props.action
            )
        }
    }
}

