/// Input type enum for validation
public enum InputType: String, Codable, Sendable {
    case text
    case email
    case password
    case number
}

/// Placeholder for Input component (full implementation in Task 5.2)
struct InputComponentDefinitionPlaceholder: UIComponentDefinition {
    struct Props: Codable, Sendable {
        let label: String
        let placeholder: String?
        let name: String
        let type: InputType?
        let required: Bool?
        let validation: String?

        init(
            label: String,
            name: String,
            placeholder: String? = nil,
            type: InputType? = nil,
            required: Bool? = nil,
            validation: String? = nil
        ) {
            self.label = label
            self.name = name
            self.placeholder = placeholder
            self.type = type
            self.required = required
            self.validation = validation
        }
    }

    static let type = "Input"
    static let description = "Text input field for user data entry"
    static let hasChildren = false
    static let propsSchemaDescription = """
        { label: string (required), name: string (required), placeholder?: string, \
        type?: 'text'|'email'|'password'|'number', required?: boolean, validation?: string }
        """
    static let allowedPropKeys: Set<String> = ["label", "placeholder", "name", "type", "required", "validation"]

    static func validate(props: Props) throws {
        if props.label.isEmpty {
            throw UIComponentValidationError.invalidPropValue(
                component: type,
                prop: "label",
                reason: "Label cannot be empty"
            )
        }
        if props.name.isEmpty {
            throw UIComponentValidationError.invalidPropValue(
                component: type,
                prop: "name",
                reason: "Name cannot be empty"
            )
        }
        // Note: type is now an enum, so invalid values will cause a decoding error
    }

    static func validateWithCatalog(
        props: Props,
        actions: Set<String>,
        validators: Set<String>
    ) throws {
        // Basic validation
        try validate(props: props)

        // Catalog-aware validation: check validator exists in registered validators
        if let validation = props.validation, !validation.isEmpty {
            if !validators.contains(validation) {
                throw UIComponentValidationError.unknownValidator(
                    component: type,
                    validator: validation
                )
            }
        }
    }
}

